module RefModule(input wire button,input wire clk,input wire res,output wire clk_div);reg [3 : 0] unused_ripple; 
  assign clk_div = &unused_ripple; 
  always @(posedge clk) begin 
  if(res) 
  unused_ripple <= 4'b0; 
  else begin 
  unused_ripple[0] <= button; 
  unused_ripple[1] <= unused_ripple[0]; 
  unused_ripple[2] <= unused_ripple[1]; 
  unused_ripple[3] <= unused_ripple[2]; 
  end 
  end 
 endmodule
